// // This module selects between two 32-bit inputs based on the select signal. When select is 0, the output is driven by in_2; when select is 1, the output is driven by in_1. If select is unknown (x), the output will be known.
module top_module(
  output [31:0] out,
  input [31:0] in_1, in_2,
  input select
);reg [31:0] out_select;
  assign out = out_select;
  always@(*) begin
	casex(select) 
		1'b0: out_select = in_1;
		1'b1: out_select = in_2;
		1'bx: out_select = 32'bx;
	endcase
  end	

endmodule
